@startuml

package "UI" {
  class LoginUI <<C>>
}

package "Controller" {
  class LoginController <<C>> {
    +login(email,password)
  }

  class ApplicationPOT <<C>> {
    +static getInstance()
    +clearCurrentSession()
  }
}

package "Model" {
  package "Service" {
    class UserService <<C>> {
      +UserService()
      +newUserSession()
    }
  }

  class UserSession <<C>> {
    -String email
    +UserSession()
  }

  abstract class User <<A>> {
    -Integer id
    -String email
    -String password
    -Integer nif
    -String name
    +User(email,password,nif,name)
  }
}

LoginUI ..> LoginController
LoginController ..> ApplicationPOT
LoginController ..> UserService

ApplicationPOT "1" --> "1" UserSession : has
UserService "1" --> "*" UserSession : creates
UserSession "1" --> "1" User : allocates

@enduml
